import * as path from 'path';
import * as fs from 'fs';

/**
 * Configuration loaded from .lasrc file
 */
export interface LasConfig {
	disabledRules: string[];
}

/**
 * Finds and parses .lasrc config file for a given file path
 * Searches from the file's directory up to the project root
 */
export function findLasConfig(filePath: string): LasConfig {
	const defaultConfig: LasConfig = { disabledRules: [] };
	
	let currentDir = path.dirname(filePath);
	const root = path.parse(currentDir).root;
	
	// Search upward for .lasrc file
	while (currentDir !== root) {
		const configPath = path.join(currentDir, '.lasrc');
		
		if (fs.existsSync(configPath)) {
			try {
				const content = fs.readFileSync(configPath, 'utf8');
				const config = JSON.parse(content);
				
				// Parse disabled rules
				if (config.disabled && Array.isArray(config.disabled)) {
					return { disabledRules: config.disabled };
				}
				
				// Also support "rules" object with false values
				if (config.rules && typeof config.rules === 'object') {
					const disabled: string[] = [];
					for (const [rule, enabled] of Object.entries(config.rules)) {
						if (enabled === false) {
							disabled.push(rule);
						}
					}
					return { disabledRules: disabled };
				}
				
				return defaultConfig;
			} catch (e) {
				// Invalid JSON, return default
				return defaultConfig;
			}
		}
		
		// Stop at project root markers
		if (fs.existsSync(path.join(currentDir, 'imports.py')) ||
		    fs.existsSync(path.join(currentDir, 'gen_decorators.py'))) {
			break;
		}
		
		currentDir = path.dirname(currentDir);
	}
	
	return defaultConfig;
}

/**
 * Finds the .lasrc config file path for a given file
 * Returns null if no config file is found
 */
export function findLasConfigPath(filePath: string): string | null {
	let currentDir = path.dirname(filePath);
	const root = path.parse(currentDir).root;
	
	while (currentDir !== root) {
		const configPath = path.join(currentDir, '.lasrc');
		
		if (fs.existsSync(configPath)) {
			return configPath;
		}
		
		// Stop at project root markers
		if (fs.existsSync(path.join(currentDir, 'imports.py')) ||
		    fs.existsSync(path.join(currentDir, 'gen_decorators.py'))) {
			break;
		}
		
		currentDir = path.dirname(currentDir);
	}
	
	return null;
}

